// ── Helpers ──────────────────────────────────────────────────

let tmpDir: string;

beforeEach(async () => {
  tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-monorepo-test-'));
});

afterEach(async () => {
  await fs.rm(tmpDir, { recursive: true, force: true });
});

// ── Spec frontmatter scope parsing ──────────────────────────

describe('monorepo: spec frontmatter scope parsing', () => {
  test('parseScope extracts scope from frontmatter', () => {
    const content = `---
scope: packages/api
depends: [base.md]
---

# API feature`;
    expect(parseScope(content)).toBe('packages/api');
  });

  test('parseScope normalizes leading/trailing slashes', () => {
    const content = `---
scope: /packages/api/
---

# Feature`;
    expect(parseScope(content)).toBe('packages/api');
  });

  test('parseScope returns undefined when no scope field', () => {
    const content = `---
depends: [base.md]
---

# Feature`;
    expect(parseScope(content)).toBeUndefined();
  });

  test('parseScope returns undefined when no frontmatter', () => {
    const content = `# Feature without frontmatter`;
    expect(parseScope(content)).toBeUndefined();
  });

  test('parseScope handles apps directory', () => {
    const content = `---
scope: apps/web
---

# Web feature`;
    expect(parseScope(content)).toBe('apps/web');
  });

  test('parseScope handles nested package paths', () => {
    const content = `---
scope: packages/shared/utils
---

# Utils feature`;
    expect(parseScope(content)).toBe('packages/shared/utils');
  });
});

