// ── Scoped setup: package-level build ───────────────────────

describe('monorepo: scoped setup detection', () => {
  test('detects package-level build script', async () => {
    // Create root with bun lockfile
    await fs.writeFile(path.join(tmpDir, 'package.json'), '{}');
    await fs.writeFile(path.join(tmpDir, 'bun.lockb'), '');

    // Create scoped package with build script
    const pkgDir = path.join(tmpDir, 'packages', 'api');
    await fs.mkdir(pkgDir, { recursive: true });
    await fs.writeFile(path.join(pkgDir, 'package.json'), JSON.stringify({
      name: '@test/api',
      scripts: { build: 'tsc -b' },
    }));

    const result = await detectScopedSetupCommands(tmpDir, 'packages/api');
    expect(result.commands.length).toBeGreaterThanOrEqual(1);
    expect(result.commands.some(c => c.includes('run build'))).toBe(true);
    expect(result.cwd).toBe(pkgDir);
  });

  test('returns empty commands when no package.json in scope', async () => {
    await fs.writeFile(path.join(tmpDir, 'package.json'), '{}');
    const pkgDir = path.join(tmpDir, 'packages', 'missing');
    await fs.mkdir(pkgDir, { recursive: true });
    // No package.json in scoped dir

    const result = await detectScopedSetupCommands(tmpDir, 'packages/missing');
    expect(result.commands.length).toBe(0);
  });

  test('returns empty when package.json has no build script', async () => {
    await fs.writeFile(path.join(tmpDir, 'package.json'), '{}');
    await fs.writeFile(path.join(tmpDir, 'bun.lockb'), '');

    const pkgDir = path.join(tmpDir, 'packages', 'no-build');
    await fs.mkdir(pkgDir, { recursive: true });
    await fs.writeFile(path.join(pkgDir, 'package.json'), JSON.stringify({
      name: '@test/no-build',
      scripts: { test: 'vitest' },
    }));

    const result = await detectScopedSetupCommands(tmpDir, 'packages/no-build');
    // Should not include a build command
    expect(result.commands.filter(c => c.includes('build'))).toHaveLength(0);
  });

  test('detects Cargo.toml in scoped directory', async () => {
    const pkgDir = path.join(tmpDir, 'packages', 'rust-service');
    await fs.mkdir(pkgDir, { recursive: true });
    await fs.writeFile(path.join(pkgDir, 'Cargo.toml'), '[package]\nname = "test"');

    const result = await detectScopedSetupCommands(tmpDir, 'packages/rust-service');
    expect(result.commands).toContain('cargo build');
  });
});

// ── Verification scoping ────────────────────────────────────

describe('monorepo: verification scoping', () => {
  test('detectVerification finds TypeScript commands at project root', async () => {
    await fs.writeFile(path.join(tmpDir, 'package.json'), JSON.stringify({
      scripts: { build: 'tsc' },
      devDependencies: { typescript: '^5.0.0' },
    }));
    await fs.writeFile(path.join(tmpDir, 'tsconfig.json'), '{}');
    await fs.writeFile(path.join(tmpDir, 'bun.lockb'), '');

    const commands = await detectVerification(tmpDir);
    expect(commands.some(c => c.includes('tsc --noEmit'))).toBe(true);
  });

  test('no verification commands for empty directory', async () => {
    const emptyDir = path.join(tmpDir, 'empty');
    await fs.mkdir(emptyDir, { recursive: true });

    const commands = await detectVerification(emptyDir);
    expect(commands.length).toBe(0);
  });

  test('detectVerification finds Go commands', async () => {
    await fs.writeFile(path.join(tmpDir, 'go.mod'), 'module test\n\ngo 1.21');

    const commands = await detectVerification(tmpDir);
    expect(commands.some(c => c.includes('go build'))).toBe(true);
    expect(commands.some(c => c.includes('go test'))).toBe(true);
  });

  test('detectVerification finds Cargo commands', async () => {
    await fs.writeFile(path.join(tmpDir, 'Cargo.toml'), '[package]\nname = "test"\nversion = "0.1.0"');

    const commands = await detectVerification(tmpDir);
    expect(commands.some(c => c.includes('cargo'))).toBe(true);
  });
});

