describe('monorepo: scope from spec content used in merge', () => {
  test('parseScope provides scope for package-scoped type-check', () => {
    const specContent = `---
scope: packages/api
depends: [auth-base.md]
---

# API endpoints
## Acceptance Criteria
- Implements REST endpoints
`;

    const scope = parseScope(specContent);
    expect(scope).toBe('packages/api');

    // This scope would be passed to runIncrementalTypeCheck(workingDir, quiet, scope)
    // in the real consolidation flow
  });

  test('spec without scope defaults to repo-root verification', () => {
    const specContent = `---
depends: [base.md]
---

# Root-level feature`;

    const scope = parseScope(specContent);
    expect(scope).toBeUndefined();
    // When scope is undefined, detectVerification() runs at root -- existing behavior
  });
});

// ── Non-overlapping package merges ──────────────────────────

describe('monorepo: non-overlapping package directories', () => {
  test('different packages target different directories (reducing conflicts)', () => {
    const pkgA = 'packages/api';
    const pkgB = 'packages/web';

    // Different packages should have non-overlapping paths
    expect(pkgA.startsWith(pkgB)).toBe(false);
    expect(pkgB.startsWith(pkgA)).toBe(false);
  });

  test('scope field correctly identifies target package', () => {
    const scopes = [
      { spec: 'api-auth.md', scope: 'packages/api' },
      { spec: 'web-ui.md', scope: 'packages/web' },
      { spec: 'shared-types.md', scope: 'packages/shared' },
    ];

    const uniqueDirs = new Set(scopes.map(s => s.scope));
    expect(uniqueDirs.size).toBe(3);
  });
});
